/* C:\Users\Edwin Boston\OneDrive\Desktop\III\STDLIB\iii\verba\base64.iii
 *
 * III STDLIB - verba::base64
 *
 * RFC 4648 Base64 encode + decode.  Standard alphabet (A-Z a-z 0-9 + / =)
 * and URL-safe alphabet (A-Z a-z 0-9 - _ , no padding).
 *
 * Public API (push to a builder):
 *   base64_encode(builder_id, src_base, src_len) -> i32
 *   base64_decode(builder_id, src_base, src_len) -> i32
 *   base64url_encode(builder_id, src_base, src_len) -> i32
 *   base64url_decode(builder_id, src_base, src_len) -> i32
 *
 * Hexad: kind_form.  Ring: R3.  K: 1.00.
 */

module verba_base64

extern @abi(c-msvc-x64) fn builder_push_byte(id: u64, b: u32) -> i32 from "builder.iii"

const B64_OK : i32 = 0i32
const B64_E_BADCHAR : i32 = -1i32
const B64_E_BADPAD : i32 = -2i32
const B64_E_BUILD : i32 = -3i32   /* a builder_push_byte failed (OOM/sealed/bad-id) -- never report truncated output as B64_OK (sibling base32.iii idiom) */

/* Encode 6-bit value to ASCII byte. */
fn b64_encode_6bit(v: u32) -> u32 {
    let m : u32 = v & 0x3Fu32
    if m < 26u32 { return 65u32 + m }              /* A-Z */
    if m < 52u32 { return 97u32 + (m - 26u32) }    /* a-z */
    if m < 62u32 { return 48u32 + (m - 52u32) }    /* 0-9 */
    if m == 62u32 { return 43u32 }                 /* + */
    return 47u32                                   /* / */
}

/* Decode ASCII byte to 6-bit value.  Returns 0xFF on invalid. */
fn b64_decode_6bit(c: u32) -> u32 {
    if c >= 65u32 {
        if c <= 90u32 { return c - 65u32 }
    }
    if c >= 97u32 {
        if c <= 122u32 { return c - 71u32 }
    }
    if c >= 48u32 {
        if c <= 57u32 { return c + 4u32 }
    }
    if c == 43u32 { return 62u32 }
    if c == 47u32 { return 63u32 }
    return 0xFFu32
}

fn base64_encode(builder_id: u64, src_base: u64, src_len: u64) -> i32 @export {
    let p : *u8 = src_base as *u8
    let mut i : u64 = 0u64
    while i + 3u64 <= src_len {
        let b0 : u32 = p[i] as u32
        let b1 : u32 = p[i + 1u64] as u32
        let b2 : u32 = p[i + 2u64] as u32
        let v : u32 = (b0 << 16u32) | (b1 << 8u32) | b2
        if builder_push_byte(builder_id, b64_encode_6bit(v >> 18u32)) != 0i32 { return B64_E_BUILD }
        if builder_push_byte(builder_id, b64_encode_6bit(v >> 12u32)) != 0i32 { return B64_E_BUILD }
        if builder_push_byte(builder_id, b64_encode_6bit(v >> 6u32)) != 0i32 { return B64_E_BUILD }
        if builder_push_byte(builder_id, b64_encode_6bit(v)) != 0i32 { return B64_E_BUILD }
        i = i + 3u64
    }
    let rem : u64 = src_len - i
    if rem == 1u64 {
        let b0 : u32 = p[i] as u32
        let v : u32 = b0 << 16u32
        if builder_push_byte(builder_id, b64_encode_6bit(v >> 18u32)) != 0i32 { return B64_E_BUILD }
        if builder_push_byte(builder_id, b64_encode_6bit(v >> 12u32)) != 0i32 { return B64_E_BUILD }
        if builder_push_byte(builder_id, 61u32) != 0i32 { return B64_E_BUILD }   /* = */
        if builder_push_byte(builder_id, 61u32) != 0i32 { return B64_E_BUILD }   /* = */
    }
    if rem == 2u64 {
        let b0 : u32 = p[i] as u32
        let b1 : u32 = p[i + 1u64] as u32
        let v : u32 = (b0 << 16u32) | (b1 << 8u32)
        if builder_push_byte(builder_id, b64_encode_6bit(v >> 18u32)) != 0i32 { return B64_E_BUILD }
        if builder_push_byte(builder_id, b64_encode_6bit(v >> 12u32)) != 0i32 { return B64_E_BUILD }
        if builder_push_byte(builder_id, b64_encode_6bit(v >> 6u32)) != 0i32 { return B64_E_BUILD }
        if builder_push_byte(builder_id, 61u32) != 0i32 { return B64_E_BUILD }   /* = */
    }
    return B64_OK
}

/* URL-safe alphabet variant (RFC 4648 §5): same encoding but with
 * '-' and '_' instead of '+' and '/'.  NO padding emitted. */
fn b64url_encode_6bit(v: u32) -> u32 {
    let m : u32 = v & 0x3Fu32
    if m < 26u32 { return 65u32 + m }
    if m < 52u32 { return 97u32 + (m - 26u32) }
    if m < 62u32 { return 48u32 + (m - 52u32) }
    if m == 62u32 { return 45u32 }   /* - instead of + */
    return 95u32                     /* _ instead of / */
}

fn base64url_encode(builder_id: u64, src_base: u64, src_len: u64) -> i32 @export {
    let p : *u8 = src_base as *u8
    let mut i : u64 = 0u64
    while i + 3u64 <= src_len {
        let b0 : u32 = p[i] as u32
        let b1 : u32 = p[i + 1u64] as u32
        let b2 : u32 = p[i + 2u64] as u32
        let v : u32 = (b0 << 16u32) | (b1 << 8u32) | b2
        if builder_push_byte(builder_id, b64url_encode_6bit(v >> 18u32)) != 0i32 { return B64_E_BUILD }
        if builder_push_byte(builder_id, b64url_encode_6bit(v >> 12u32)) != 0i32 { return B64_E_BUILD }
        if builder_push_byte(builder_id, b64url_encode_6bit(v >> 6u32)) != 0i32 { return B64_E_BUILD }
        if builder_push_byte(builder_id, b64url_encode_6bit(v)) != 0i32 { return B64_E_BUILD }
        i = i + 3u64
    }
    let rem : u64 = src_len - i
    if rem == 1u64 {
        let b0 : u32 = p[i] as u32
        let v : u32 = b0 << 16u32
        if builder_push_byte(builder_id, b64url_encode_6bit(v >> 18u32)) != 0i32 { return B64_E_BUILD }
        if builder_push_byte(builder_id, b64url_encode_6bit(v >> 12u32)) != 0i32 { return B64_E_BUILD }
        /* URL-safe omits padding */
    }
    if rem == 2u64 {
        let b0 : u32 = p[i] as u32
        let b1 : u32 = p[i + 1u64] as u32
        let v : u32 = (b0 << 16u32) | (b1 << 8u32)
        if builder_push_byte(builder_id, b64url_encode_6bit(v >> 18u32)) != 0i32 { return B64_E_BUILD }
        if builder_push_byte(builder_id, b64url_encode_6bit(v >> 12u32)) != 0i32 { return B64_E_BUILD }
        if builder_push_byte(builder_id, b64url_encode_6bit(v >> 6u32)) != 0i32 { return B64_E_BUILD }
    }
    return B64_OK
}

/* URL-safe decode.  Input is unpadded (no '=').  Maps '-'->62, '_'->63.
 * '+' '/' '=' are all BADCHAR.  Remainder of 1 char is BADPAD (invalid
 * encoding length -- no byte boundary lands on 6 bits). */
fn b64url_decode_6bit(c: u32) -> u32 {
    if c >= 65u32 {
        if c <= 90u32 { return c - 65u32 }      /* A-Z -> 0..25 */
    }
    if c >= 97u32 {
        if c <= 122u32 { return c - 71u32 }     /* a-z -> 26..51 */
    }
    if c >= 48u32 {
        if c <= 57u32 { return c + 4u32 }       /* 0-9 -> 52..61 */
    }
    if c == 45u32 { return 62u32 }              /* '-' -> 62 */
    if c == 95u32 { return 63u32 }              /* '_' -> 63 */
    return 0xFFu32                              /* '+' '/' '=' and all others: BADCHAR */
}

fn base64url_decode(builder_id: u64, src_base: u64, src_len: u64) -> i32 @export {
    let p : *u8 = src_base as *u8
    let mut i : u64 = 0u64
    /* Full 4-char groups -> 3 bytes each. */
    while i + 4u64 <= src_len {
        let c0 : u32 = p[i] as u32
        let c1 : u32 = p[i + 1u64] as u32
        let c2 : u32 = p[i + 2u64] as u32
        let c3 : u32 = p[i + 3u64] as u32
        let d0 : u32 = b64url_decode_6bit(c0)
        let d1 : u32 = b64url_decode_6bit(c1)
        let d2 : u32 = b64url_decode_6bit(c2)
        let d3 : u32 = b64url_decode_6bit(c3)
        if d0 == 0xFFu32 { return B64_E_BADCHAR }
        if d1 == 0xFFu32 { return B64_E_BADCHAR }
        if d2 == 0xFFu32 { return B64_E_BADCHAR }
        if d3 == 0xFFu32 { return B64_E_BADCHAR }
        let v : u32 = (d0 << 18u32) | (d1 << 12u32) | (d2 << 6u32) | d3
        if builder_push_byte(builder_id, (v >> 16u32) & 0xFFu32) != 0i32 { return B64_E_BUILD }
        if builder_push_byte(builder_id, (v >> 8u32) & 0xFFu32) != 0i32 { return B64_E_BUILD }
        if builder_push_byte(builder_id, v & 0xFFu32) != 0i32 { return B64_E_BUILD }
        i = i + 4u64
    }
    /* Handle unpadded tail (0, 2, or 3 remaining chars). */
    let tail : u64 = src_len - i
    if tail == 0u64 { return B64_OK }
    if tail == 1u64 { return B64_E_BADPAD }     /* 6 bits: no complete byte */
    if tail == 2u64 {
        /* 2 chars -> 12 bits -> 1 byte (low 4 bits of d1 are padding, must be 0). */
        let c0 : u32 = p[i] as u32
        let c1 : u32 = p[i + 1u64] as u32
        let d0 : u32 = b64url_decode_6bit(c0)
        let d1 : u32 = b64url_decode_6bit(c1)
        if d0 == 0xFFu32 { return B64_E_BADCHAR }
        if d1 == 0xFFu32 { return B64_E_BADCHAR }
        if builder_push_byte(builder_id, ((d0 << 2u32) | (d1 >> 4u32)) & 0xFFu32) != 0i32 { return B64_E_BUILD }
        return B64_OK
    }
    /* tail == 3: 3 chars -> 18 bits -> 2 bytes (low 2 bits of d2 are padding, must be 0). */
    let c0 : u32 = p[i] as u32
    let c1 : u32 = p[i + 1u64] as u32
    let c2 : u32 = p[i + 2u64] as u32
    let d0 : u32 = b64url_decode_6bit(c0)
    let d1 : u32 = b64url_decode_6bit(c1)
    let d2 : u32 = b64url_decode_6bit(c2)
    if d0 == 0xFFu32 { return B64_E_BADCHAR }
    if d1 == 0xFFu32 { return B64_E_BADCHAR }
    if d2 == 0xFFu32 { return B64_E_BADCHAR }
    if builder_push_byte(builder_id, ((d0 << 2u32) | (d1 >> 4u32)) & 0xFFu32) != 0i32 { return B64_E_BUILD }
    if builder_push_byte(builder_id, ((d1 << 4u32) | (d2 >> 2u32)) & 0xFFu32) != 0i32 { return B64_E_BUILD }
    return B64_OK
}

fn base64_decode(builder_id: u64, src_base: u64, src_len: u64) -> i32 @export {
    let p : *u8 = src_base as *u8
    let mut i : u64 = 0u64
    while i + 4u64 <= src_len {
        let c0 : u32 = p[i] as u32
        let c1 : u32 = p[i + 1u64] as u32
        let c2 : u32 = p[i + 2u64] as u32
        let c3 : u32 = p[i + 3u64] as u32
        let d0 : u32 = b64_decode_6bit(c0)
        let d1 : u32 = b64_decode_6bit(c1)
        if d0 == 0xFFu32 { return B64_E_BADCHAR }
        if d1 == 0xFFu32 { return B64_E_BADCHAR }
        if c2 == 61u32 {
            /* "XX==" -> 1 byte */
            if c3 != 61u32 { return B64_E_BADPAD }
            let v : u32 = (d0 << 18u32) | (d1 << 12u32)
            if builder_push_byte(builder_id, (v >> 16u32) & 0xFFu32) != 0i32 { return B64_E_BUILD }
            i = i + 4u64
        } else {
            let d2 : u32 = b64_decode_6bit(c2)
            if d2 == 0xFFu32 { return B64_E_BADCHAR }
            if c3 == 61u32 {
                /* "XXX=" -> 2 bytes */
                let v : u32 = (d0 << 18u32) | (d1 << 12u32) | (d2 << 6u32)
                if builder_push_byte(builder_id, (v >> 16u32) & 0xFFu32) != 0i32 { return B64_E_BUILD }
                if builder_push_byte(builder_id, (v >> 8u32) & 0xFFu32) != 0i32 { return B64_E_BUILD }
                i = i + 4u64
            } else {
                let d3 : u32 = b64_decode_6bit(c3)
                if d3 == 0xFFu32 { return B64_E_BADCHAR }
                let v : u32 = (d0 << 18u32) | (d1 << 12u32) | (d2 << 6u32) | d3
                if builder_push_byte(builder_id, (v >> 16u32) & 0xFFu32) != 0i32 { return B64_E_BUILD }
                if builder_push_byte(builder_id, (v >> 8u32) & 0xFFu32) != 0i32 { return B64_E_BUILD }
                if builder_push_byte(builder_id, v & 0xFFu32) != 0i32 { return B64_E_BUILD }
                i = i + 4u64
            }
        }
    }
    /* RFC 4648 §3.1: valid Base64 is padded to a multiple of 4; 1-3 unparsed trailing
     * bytes are malformed (silently dropping them would accept truncated input). */
    if (src_len - i) != 0u64 { return B64_E_BADPAD }
    return B64_OK
}

/* KAT: base64url_encode + base64url_decode
 *
 * Exercises:
 *   - Full-group round-trip with bytes that produce sextets 62/63 (-/_)
 *     proving the alphabet swap is real (not just A-Z a-z 0-9 sharing).
 *   - Tail-2 round-trip: 1-byte input -> 2-char unpadded output.
 *   - Tail-3 round-trip: 2-byte input -> 3-char unpadded output.
 *   - Standard base64_decode REJECTS url-safe '-' (BADCHAR negative).
 *   - base64url_decode REJECTS standard '+' (BADCHAR negative).
 *   - base64url_decode REJECTS '=' padding (BADCHAR negative).
 *   - base64url_decode REJECTS 1-char tail (BADPAD negative).
 */
module corpus_1000

extern @abi(c-msvc-x64) fn malloc(n: u64) -> *u8 from "msvcrt"
extern @abi(c-msvc-x64) fn free(p: *u8) -> u64 from "msvcrt"
extern @abi(c-msvc-x64) fn arena_new(bytes: u64) -> u64 from "arena.iii"
extern @abi(c-msvc-x64) fn arena_drop(id: u64) -> i32 from "arena.iii"
extern @abi(c-msvc-x64) fn builder_new(arena: u64, hint: u64) -> u64 from "builder.iii"
extern @abi(c-msvc-x64) fn builder_seal(id: u64) -> u64 from "builder.iii"
extern @abi(c-msvc-x64) fn builder_len(id: u64) -> u64 from "builder.iii"
extern @abi(c-msvc-x64) fn base64_decode(builder_id: u64, src_base: u64, src_len: u64) -> i32 from "base64.iii"
extern @abi(c-msvc-x64) fn base64url_encode(builder_id: u64, src_base: u64, src_len: u64) -> i32 from "base64.iii"
extern @abi(c-msvc-x64) fn base64url_decode(builder_id: u64, src_base: u64, src_len: u64) -> i32 from "base64.iii"

fn main() -> u64 {
    let a : u64 = arena_new(1u64 << 16u64)

    /* --- TEST 1: full-group round-trip + alphabet proof ---
     * Input: [0xFB, 0xFF, 0xFF]  (3 bytes, one full 4-char group)
     * Expected encode: "-___"  (sextets 62, 63, 63, 63)
     * This proves '-' and '_' are actually emitted, not just A-Z/0-9. */
    let src3 : *u8 = malloc(3u64)
    src3[0] = 0xFBu8
    src3[1] = 0xFFu8
    src3[2] = 0xFFu8
    let enc3_b : u64 = builder_new(a, 8u64)
    if base64url_encode(enc3_b, src3 as u64, 3u64) != 0i32 { return 1u64 }
    if builder_len(enc3_b) != 4u64 { return 2u64 }
    let enc3 : *u8 = builder_seal(enc3_b) as *u8
    if enc3[0] != 45u8  { return 3u64 }    /* '-' (sextet 62) */
    if enc3[1] != 95u8  { return 4u64 }    /* '_' (sextet 63) */
    if enc3[2] != 95u8  { return 5u64 }    /* '_' */
    if enc3[3] != 95u8  { return 6u64 }    /* '_' */
    /* Decode round-trip */
    let dec3_b : u64 = builder_new(a, 8u64)
    if base64url_decode(dec3_b, enc3 as u64, 4u64) != 0i32 { return 7u64 }
    if builder_len(dec3_b) != 3u64 { return 8u64 }
    let dec3 : *u8 = builder_seal(dec3_b) as *u8
    if dec3[0] != 0xFBu8 { return 9u64 }
    if dec3[1] != 0xFFu8 { return 10u64 }
    if dec3[2] != 0xFFu8 { return 11u64 }

    /* --- TEST 2: tail-2 (1-byte input -> 2-char unpadded) ---
     * Input: [0xF8]  sextets: 62('-'), 0('A')  -> "-A" */
    let src1 : *u8 = malloc(1u64)
    src1[0] = 0xF8u8
    let enc1_b : u64 = builder_new(a, 8u64)
    if base64url_encode(enc1_b, src1 as u64, 1u64) != 0i32 { return 12u64 }
    if builder_len(enc1_b) != 2u64 { return 13u64 }
    let enc1 : *u8 = builder_seal(enc1_b) as *u8
    if enc1[0] != 45u8  { return 14u64 }   /* '-' */
    if enc1[1] != 65u8  { return 15u64 }   /* 'A' */
    /* Decode round-trip */
    let dec1_b : u64 = builder_new(a, 8u64)
    if base64url_decode(dec1_b, enc1 as u64, 2u64) != 0i32 { return 16u64 }
    if builder_len(dec1_b) != 1u64 { return 17u64 }
    let dec1 : *u8 = builder_seal(dec1_b) as *u8
    if dec1[0] != 0xF8u8 { return 18u64 }

    /* --- TEST 3: tail-3 (2-byte input -> 3-char unpadded) ---
     * Input: [0xFB, 0xFF]  sextets: 62('-'), 63('_'), 60('8')  -> "-_8" */
    let src2 : *u8 = malloc(2u64)
    src2[0] = 0xFBu8
    src2[1] = 0xFFu8
    let enc2_b : u64 = builder_new(a, 8u64)
    if base64url_encode(enc2_b, src2 as u64, 2u64) != 0i32 { return 19u64 }
    if builder_len(enc2_b) != 3u64 { return 20u64 }
    let enc2 : *u8 = builder_seal(enc2_b) as *u8
    if enc2[0] != 45u8  { return 21u64 }   /* '-' (sextet 62) */
    if enc2[1] != 95u8  { return 22u64 }   /* '_' (sextet 63) */
    if enc2[2] != 56u8  { return 23u64 }   /* '8' (sextet 60: 48+(60-52)=56) */
    /* Decode round-trip */
    let dec2_b : u64 = builder_new(a, 8u64)
    if base64url_decode(dec2_b, enc2 as u64, 3u64) != 0i32 { return 24u64 }
    if builder_len(dec2_b) != 2u64 { return 25u64 }
    let dec2 : *u8 = builder_seal(dec2_b) as *u8
    if dec2[0] != 0xFBu8 { return 26u64 }
    if dec2[1] != 0xFFu8 { return 27u64 }

    /* --- NEGATIVE 1: standard base64_decode rejects '-' (url char, not standard) ---
     * Feed the "-___" output from test 1 to the STANDARD decoder: must get BADCHAR. */
    let neg1_b : u64 = builder_new(a, 8u64)
    let neg1_rc : i32 = base64_decode(neg1_b, enc3 as u64, 4u64)
    if neg1_rc == 0i32 { return 30u64 }    /* standard decoder MUST reject '-'; rc=0 is wrong */

    /* --- NEGATIVE 2: base64url_decode rejects '+' (standard char, not url) ---
     * Build a 4-char string with '+' at position 0: "+Aaa" */
    let neg2_buf : *u8 = malloc(4u64)
    neg2_buf[0] = 43u8   /* '+' */
    neg2_buf[1] = 65u8   /* 'A' */
    neg2_buf[2] = 97u8   /* 'a' */
    neg2_buf[3] = 97u8   /* 'a' */
    let neg2_b : u64 = builder_new(a, 8u64)
    let neg2_rc : i32 = base64url_decode(neg2_b, neg2_buf as u64, 4u64)
    if neg2_rc == 0i32 { return 31u64 }    /* url decoder MUST reject '+' */

    /* --- NEGATIVE 3: base64url_decode rejects '=' padding ---
     * "AA==" is valid standard base64 but '=' is BADCHAR in url mode. */
    let neg3_buf : *u8 = malloc(4u64)
    neg3_buf[0] = 65u8   /* 'A' */
    neg3_buf[1] = 65u8   /* 'A' */
    neg3_buf[2] = 61u8   /* '=' */
    neg3_buf[3] = 61u8   /* '=' */
    let neg3_b : u64 = builder_new(a, 8u64)
    let neg3_rc : i32 = base64url_decode(neg3_b, neg3_buf as u64, 4u64)
    if neg3_rc == 0i32 { return 32u64 }    /* url decoder MUST reject '=' */

    /* --- NEGATIVE 4: base64url_decode rejects 1-char tail (BADPAD) ---
     * A single char is 6 bits; no byte boundary exists. */
    let neg4_buf : *u8 = malloc(5u64)
    neg4_buf[0] = 65u8   /* 'A' -- a valid 4-char group */
    neg4_buf[1] = 65u8
    neg4_buf[2] = 65u8
    neg4_buf[3] = 65u8
    neg4_buf[4] = 65u8   /* 1 extra char: tail==1 -> BADPAD */
    let neg4_b : u64 = builder_new(a, 8u64)
    let neg4_rc : i32 = base64url_decode(neg4_b, neg4_buf as u64, 5u64)
    if neg4_rc == 0i32 { return 33u64 }    /* must reject 1-char tail */

    free(src3); free(src1); free(src2)
    free(neg2_buf); free(neg3_buf); free(neg4_buf)
    arena_drop(a)
    return 99u64
}
